109→    id: crypto.randomUUID(),
110→    idempotencyKey: crypto.randomUUID(),
111→    payload,
112→    status: 'pending',
113→    attempts: 0,
114→    retryCount: 0,
115→    createdAt: now,
116→    updatedAt: now
117→  };
118→  await putItem(item);
119→  return item;
120→}
