 76→function parseDateIso(input: unknown): string | null {
 77→  if (!input) return null;
 78→  if (input instanceof Date) {
 79→    if (Number.isNaN(input.getTime())) return null;
 80→    return input.toISOString();
 81→  }
 82→  if (typeof input === "string") {
 83→    const value = input.trim();
 84→    if (!value) return null;
 85→    const exifMatch = value.match(EXIF_DATE_TIME_REGEX);
 86→    if (exifMatch) {
 87→      const year = Number(exifMatch[1]);
 88→      const month = Number(exifMatch[2]);
 89→      const day = Number(exifMatch[3]);
 90→      const hour = Number(exifMatch[4]);
 91→      const minute = Number(exifMatch[5]);
 92→      const second = Number(exifMatch[6]);
 93→      const millisRaw = exifMatch[7] ?? "0";
 94→      const millis = Number(millisRaw.slice(0, 3).padEnd(3, "0"));
 95→      const utcDate = new Date(Date.UTC(year, month - 1, day, hour, minute, second, millis));
 96→      if (!Number.isNaN(utcDate.getTime())) return utcDate.toISOString();
 97→    }
 98→    const parsed = new Date(value);
 99→    if (Number.isNaN(parsed.getTime())) return null;
100→    return parsed.toISOString();
101→  }
102→  if (typeof input === "number") {
103→    const parsed = new Date(input);
104→    if (Number.isNaN(parsed.getTime())) return null;
105→    return parsed.toISOString();
106→  }
107→  if (typeof input === "object") {
108→    const value = input as {
109→      toDate?: () => unknown;
110→      toISOString?: () => string;
111→      value?: unknown;
112→      rawValue?: unknown;
113→      year?: unknown;
114→      month?: unknown;
115→      day?: unknown;
116→      hour?: unknown;
117→      minute?: unknown;
118→      second?: unknown;
119→      millisecond?: unknown;
120→    };
121→    if (typeof value.toDate === "function") {
122→      try {
123→        const converted = value.toDate();
124→        const parsed = parseDateIso(converted);
125→        if (parsed) return parsed;
126→      } catch {
127→        // fall through
128→      }
129→    }
130→    if (typeof value.toISOString === "function") {
131→      try {
132→        const iso = value.toISOString();
133→        const parsed = parseDateIso(iso);
134→        if (parsed) return parsed;
135→      } catch {
136→        // fall through
137→      }
138→    }
139→    const fromValue = parseDateIso(value.value ?? value.rawValue);
140→    if (fromValue) return fromValue;
141→
142→    const year = Number(value.year);
143→    const month = Number(value.month);
144→    const day = Number(value.day);
145→    if (Number.isFinite(year) && Number.isFinite(month) && Number.isFinite(day)) {
146→      const hour = Number(value.hour);
147→      const minute = Number(value.minute);
148→      const second = Number(value.second);
149→      const millisecond = Number(value.millisecond);
150→      const utcDate = new Date(
151→        Date.UTC(
152→          year,
153→          month - 1,
154→          day,
155→          Number.isFinite(hour) ? hour : 0,
156→          Number.isFinite(minute) ? minute : 0,
157→          Number.isFinite(second) ? second : 0,
158→          Number.isFinite(millisecond) ? millisecond : 0,
159→        ),
160→      );
161→      if (!Number.isNaN(utcDate.getTime())) return utcDate.toISOString();
162→    }
163→  }
164→  return null;
165→}
