239→function parseDmsCoordinate(input: unknown): number | null {
240→  const direct = toRationalNumber(input);
241→  if (direct !== null) return direct;
242→  if (!Array.isArray(input) || input.length === 0) return null;
243→  const degrees = toRationalNumber(input[0]);
244→  if (degrees === null) return null;
245→  const minutes = toRationalNumber(input[1]) ?? 0;
246→  const seconds = toRationalNumber(input[2]) ?? 0;
247→  return degrees + minutes / 60 + seconds / 3600;
248→}
