290→function detectImageFormat(imageBuffer: Buffer): "jpeg" | "png" | "webp" | "heic" | "heif" | "unknown" {
291→  if (imageBuffer.length >= 3 && imageBuffer[0] === 0xff && imageBuffer[1] === 0xd8 && imageBuffer[2] === 0xff) {
292→    return "jpeg";
293→  }
294→  if (
295→    imageBuffer.length >= 8 &&
296→    imageBuffer[0] === 0x89 &&
297→    imageBuffer[1] === 0x50 &&
298→    imageBuffer[2] === 0x4e &&
299→    imageBuffer[3] === 0x47
300→  ) {
301→    return "png";
302→  }
303→  if (imageBuffer.length >= 12) {
304→    const riff = imageBuffer.subarray(0, 4).toString("ascii");
305→    const webp = imageBuffer.subarray(8, 12).toString("ascii");
306→    if (riff === "RIFF" && webp === "WEBP") return "webp";
307→  }
308→  if (imageBuffer.length >= 12 && imageBuffer.subarray(4, 8).toString("ascii") === "ftyp") {
309→    const brand = imageBuffer.subarray(8, 12).toString("ascii").toLowerCase();
310→    if (brand.startsWith("heic") || brand.startsWith("heix") || brand.startsWith("hevc") || brand.startsWith("hevx")) {
311→      return "heic";
312→    }
313→    if (brand === "heif" || brand === "mif1" || brand === "msf1") {
314→      return "heif";
315→    }
316→  }
317→  return "unknown";
318→}
